import { serializeMarkerRange } from '../../../utils/serialize-marker-range.js';
import { IndicatorData } from '../types.js';

export const extractUniqueIndicatorsByPriority = (
  indicators: IndicatorData[][],
) => {
  const indicatorsByTrack: [string, IndicatorData][][] = [];
  indicators.forEach((track, index) => {
    indicatorsByTrack[index] = [];
    const map = track.reduce((uniqueIndicators, indicator) => {
      const key = serializeMarkerRange(
        {
          start: indicator.start.valueOf(),
          end: indicator.end ? indicator.end.valueOf() : undefined,
        },
        index,
      );

      if (!uniqueIndicators.has(key)) {
        uniqueIndicators.set(key, indicator);
      } else {
        // eslint-disable-next-line @typescript-eslint/no-non-null-assertion
        const value = uniqueIndicators.get(key)!;

        if (
          indicator.priority &&
          (!value.priority || value.priority < indicator.priority)
        ) {
          uniqueIndicators.set(key, indicator);
        }
      }

      return uniqueIndicators;
    }, new Map<string, IndicatorData>());
    indicatorsByTrack[index] = Array.from(map.entries());
  });

  return indicatorsByTrack;
};
